// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./RoleManager.sol";

contract SupplyChain {

    RoleManager public roleManager;

    constructor(address _roleManagerAddress) {
        roleManager = RoleManager(_roleManagerAddress);
    }

    enum ProductState {
        CREATED,
        IN_DISTRIBUTION,
        IN_PHARMACY,
        SOLD
    }

    struct TransportLog {
        string location;
        int256 temperature;
        uint256 timestamp;
    }

    struct Product {
        string productId;
        address manufacturer;
        address currentOwner;
        uint256 manufactureDate;
        uint256 expiryDate;
        ProductState state;
        bool exists;
        TransportLog[] transportHistory;
    }

    mapping(string => Product) private products;

    event ProductCreated(string productId, address manufacturer);
    event OwnershipTransferred(string productId, address from, address to);
    event TransportLogged(string productId, string location, int256 temperature);

    modifier onlyManufacturer() {
        require(roleManager.isManufacturer(msg.sender), "Not manufacturer");
        _;
    }

    modifier onlyCurrentOwner(string memory _productId) {
        require(products[_productId].currentOwner == msg.sender, "Not current owner");
        _;
    }

    modifier productExists(string memory _productId) {
        require(products[_productId].exists, "Product does not exist");
        _;
    }

    // 🔹 Create Product
    function createProduct(
        string memory _productId,
        uint256 _manufactureDate,
        uint256 _expiryDate
    ) public onlyManufacturer {

        require(!products[_productId].exists, "Product already exists");
        require(_expiryDate > _manufactureDate, "Invalid dates");

        Product storage newProduct = products[_productId];
        newProduct.productId = _productId;
        newProduct.manufacturer = msg.sender;
        newProduct.currentOwner = msg.sender;
        newProduct.manufactureDate = _manufactureDate;
        newProduct.expiryDate = _expiryDate;
        newProduct.state = ProductState.CREATED;
        newProduct.exists = true;

        emit ProductCreated(_productId, msg.sender);
    }

    // 🔹 Transfer Product
    function transferProduct(
        string memory _productId,
        address _to
    )
        public
        productExists(_productId)
        onlyCurrentOwner(_productId)
    {
        require(block.timestamp < products[_productId].expiryDate, "Product expired");

        RoleManager.Role senderRole = roleManager.getRole(msg.sender);
        RoleManager.Role receiverRole = roleManager.getRole(_to);

        // Enforce strict supply chain order
        if (senderRole == RoleManager.Role.MANUFACTURER) {
            require(receiverRole == RoleManager.Role.DISTRIBUTOR, "Must transfer to distributor");
            products[_productId].state = ProductState.IN_DISTRIBUTION;
        }
        else if (senderRole == RoleManager.Role.DISTRIBUTOR) {
            require(receiverRole == RoleManager.Role.PHARMACY, "Must transfer to pharmacy");
            products[_productId].state = ProductState.IN_PHARMACY;
        }
        else if (senderRole == RoleManager.Role.PHARMACY) {
            products[_productId].state = ProductState.SOLD;
        }
        else {
            revert("Invalid role transfer");
        }

        address previousOwner = products[_productId].currentOwner;
        products[_productId].currentOwner = _to;

        emit OwnershipTransferred(_productId, previousOwner, _to);
    }

    // 🔹 Add Transport Log
    function addTransportLog(
        string memory _productId,
        string memory _location,
        int256 _temperature
    )
        public
        productExists(_productId)
        onlyCurrentOwner(_productId)
    {
        products[_productId].transportHistory.push(
            TransportLog({
                location: _location,
                temperature: _temperature,
                timestamp: block.timestamp
            })
        );

        emit TransportLogged(_productId, _location, _temperature);
    }

    // 🔹 View Product Details
    function getProduct(string memory _productId)
        public
        view
        productExists(_productId)
        returns (
            address manufacturer,
            address currentOwner,
            uint256 manufactureDate,
            uint256 expiryDate,
            ProductState state
        )
    {
        Product storage p = products[_productId];

        return (
            p.manufacturer,
            p.currentOwner,
            p.manufactureDate,
            p.expiryDate,
            p.state
        );
    }
}

